def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    original_ppt = Presentation(original_ppt_path)
    modified_ppt = Presentation(modified_ppt_path)

    original_count = len(original_ppt.slides)
    modified_count = len(modified_ppt.slides)

    if modified_count != original_count + 1:
        return "Cannot verify position - slide count is incorrect", 0.0

    # Check if slides 1-3 remain unchanged by comparing their content
    try:
        for i in range(3):  # slides 0, 1, 2 (1st, 2nd, 3rd slides)
            orig_slide = original_ppt.slides[i]
            mod_slide = modified_ppt.slides[i]

            # Basic check - compare number of shapes
            if len(orig_slide.shapes) != len(mod_slide.shapes):
                return f"Original slide {i+1} appears to have been modified", 0.0

        return "New slide appears to be correctly positioned after slide 3", 1.0
    except Exception as e:
        return f"Error verifying slide position: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    original_ppt = Presentation(original_ppt_path)
    modified_ppt = Presentation(modified_ppt_path)

    if len(modified_ppt.slides) < 3:
        return "Less than 3 slides in modified presentation", 0.0

    # Check if slides 2 and 3 have similar structure (shape count)
    try:
        orig_slide2_shapes = len(original_ppt.slides[1].shapes)
        orig_slide3_shapes = len(original_ppt.slides[2].shapes)

        mod_slide2_shapes = len(modified_ppt.slides[1].shapes)
        mod_slide3_shapes = len(modified_ppt.slides[2].shapes)

        if orig_slide2_shapes == mod_slide2_shapes and orig_slide3_shapes == mod_slide3_shapes:
            return "Slides 2 and 3 appear to be preserved with same structure", 1.0
        else:
            return f"Slides 2 or 3 structure changed: orig(2:{orig_slide2_shapes}, 3:{orig_slide3_shapes}) vs mod(2:{mod_slide2_shapes}, 3:{mod_slide3_shapes})", 0.0
    except Exception as e:
        return f"Error checking slide preservation: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE

    modified_ppt = Presentation(modified_ppt_path)

    if len(modified_ppt.slides) < 4:
        return "New slide does not exist", 0.0

    new_slide = modified_ppt.slides[3]  # 4th slide (index 3)

    # Look for table shapes
    table_count = 0
    for shape in new_slide.shapes:
        if shape.shape_type == MSO_SHAPE_TYPE.TABLE:
            table_count += 1

    if table_count > 0:
        return f"Found {table_count} table(s) on the new slide", 1.0
    else:
        return "No table found on the new slide", 0.0

