def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Find screenshots for slides 2, 3, and the new slide 4
    slide2_screenshot = None
    slide3_screenshot = None
    new_slide_screenshot = None

    for screenshot in original_ppt_screenshots:
        if screenshot.slide_number == 2:
            slide2_screenshot = screenshot
        elif screenshot.slide_number == 3:
            slide3_screenshot = screenshot

    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 4:
            new_slide_screenshot = screenshot

    if not all([slide2_screenshot, slide3_screenshot, new_slide_screenshot]):
        raise ScreenshotsUnavailableError("Cannot find required slide screenshots; flagging task for verification retry.")

    prompt = """I will show you three PowerPoint slides:
    1. Original slide 2
    2. Original slide 3  
    3. New combined slide

    Please analyze whether the new combined slide contains images/visual elements that appear to come from both original slides 2 and 3. Look for similar clothing items, product images, or visual elements that have been transferred to the new slide.

    Respond with 'YES' if you can identify images/elements from both slides 2 and 3 in the new slide, or 'NO' if images from one or both slides are missing. Provide a brief explanation of what you observed."""

    try:
        response = vlm_call(prompt, [
            slide2_screenshot.image_path,
            slide3_screenshot.image_path, 
            new_slide_screenshot.image_path
        ], temperature=0.1)

        if response.upper().startswith('YES'):
            return f"VLM confirmed images from both slides are present: {response}", 1.0
        else:
            return f"VLM did not find images from both slides: {response}", 0.0
    except Exception as e:
        return f"Error in VLM call: {str(e)}", 0.0

